'use strict';

function assertEl(sel) {
  const el = document.querySelector(sel);
  if (el === null) console.error(`[frete] elemento não encontrado: ${sel}`);
  return el;
}

function toNumberOrNull(raw) {
  if (raw === null || raw === undefined) return null;
  const s = String(raw).trim().replace(',', '.');
  if (s.length === 0) return null;
  const n = Number(s);
  return Number.isNaN(n) ? null : n;
}

function normalizarCupom(raw) {
  const s = String(raw ?? '').trim().toUpperCase();
  return s.length === 0 ? null : s;
}

function formatarBRL(v) {
  const n = Number(v);
  return Number.isFinite(n) ? `R$ ${n.toFixed(2)}` : '—';
}

const BASE_REGIAO = {
  SUL: 12,
  SUDESTE: 10,
  'CENTRO-OESTE': 14,
  NORDESTE: 18,
  NORTE: 22,
};

function isRegiaoValida(r) {
  return Object.prototype.hasOwnProperty.call(BASE_REGIAO, r);
}

function ajustePorPeso(pesoKg) {
  if (pesoKg <= 1) return 0;
  if (pesoKg <= 5) return 8;
  return 15;
}

function calcularFrete({ regiao, pesoKg, subtotal, cupom }) {
  if (!isRegiaoValida(regiao)) return { ok: false, msg: 'regiao inválida' };
  if (!Number.isFinite(pesoKg) || pesoKg <= 0) return { ok: false, msg: 'peso inválido' };
  if (!Number.isFinite(subtotal) || subtotal < 0) return { ok: false, msg: 'subtotal inválido' };

  const motivos = [];
  const cupomNorm = normalizarCupom(cupom);

  if (subtotal >= 300) {
    motivos.push('Frete grátis: subtotal >= 300');
    return { ok: true, frete: 0, total: subtotal, motivos };
  }

  if (cupomNorm === 'FRETE') {
    motivos.push('Cupom FRETE: frete 0');
    return { ok: true, frete: 0, total: subtotal, motivos };
  }

  if (cupomNorm !== null) motivos.push(`Cupom ignorado: ${cupomNorm}`);

  const base = BASE_REGIAO[regiao];
  motivos.push(`Base região ${regiao}: ${formatarBRL(base)}`);

  const ajuste = ajustePorPeso(pesoKg);
  motivos.push(`Ajuste por peso (${pesoKg}kg): ${formatarBRL(ajuste)}`);

  const frete = base + ajuste;
  const total = subtotal + frete;
  return { ok: true, frete, total, motivos };
}

const form = assertEl('#form');
const elRegiao = assertEl('#regiao');
const elPeso = assertEl('#peso');
const elSubtotal = assertEl('#subtotal');
const elCupom = assertEl('#cupom');
const elResumo = assertEl('#resumo');
const elMotivos = assertEl('#motivos');

const hasDom = Boolean(form && elRegiao && elPeso && elSubtotal && elCupom && elResumo && elMotivos);

function render(res) {
  if (!hasDom) return;
  elMotivos.innerHTML = '';

  if (!res.ok) {
    elResumo.textContent = `Erro: ${res.msg}`;
    return;
  }

  elResumo.textContent = `Frete: ${formatarBRL(res.frete)} | Total: ${formatarBRL(res.total)}`;
  for (const m of res.motivos) {
    const li = document.createElement('li');
    li.textContent = m;
    elMotivos.appendChild(li);
  }
}

function onSubmit(ev) {
  ev.preventDefault();
  if (!hasDom) return;

  const regiao = String(elRegiao.value);
  const pesoKg = toNumberOrNull(elPeso.value);
  const subtotal = toNumberOrNull(elSubtotal.value);
  const cupom = elCupom.value;

  if (pesoKg === null || subtotal === null) {
    return render({ ok: false, msg: 'peso e subtotal devem ser números' });
  }

  return render(calcularFrete({ regiao, pesoKg, subtotal, cupom }));
}

if (hasDom) {
  form.addEventListener('submit', onSubmit);
  console.log('[frete] pronto');
}
